#!/bin/bash
cd "$(dirname "$0")/../.."
set -e

echo "Exporting Poetry dependencies to requirements files..."

mkdir -p var

POETRY="poetry"

# Warning comment to prepend to generated files
WARNING="# WARNING: This file is auto-generated by ./scripts/shell/export-requirements.sh
# Do NOT edit this file directly - changes will be overwritten!
# To modify dependencies, edit pyproject.toml or the export script instead.
# Generated files are stored in var/ directory.
#"

export_requirements() {
    local output=$1
    local group=$2
    shift 2
    $POETRY export --format requirements.txt --output "$output" --without-hashes --only="$group" "$@"
    # Prepend warning comment
    sed -i "1i\\$WARNING" "$output"
}

$POETRY export --format requirements.txt --output var/requirements.txt --without-hashes
sed -i "1i\\$WARNING" var/requirements.txt

$POETRY export --format requirements.txt --output var/requirements-dev.txt --without-hashes --with dev
sed -i "1i\\$WARNING" var/requirements-dev.txt

export_requirements var/requirements-api.txt api
export_requirements var/requirements-create-buckets.txt create-buckets
export_requirements var/requirements-create-tables.txt create-tables
export_requirements var/requirements-create-topics.txt create-topics
export_requirements var/requirements-idworker.txt idworker
export_requirements var/requirements-stats-worker.txt stats-worker
export_requirements var/requirements-json-worker.txt json-worker
export_requirements var/requirements-ttl-worker.txt ttl-worker
export_requirements var/requirements-purge-worker.txt purge-worker

echo "Requirements files updated successfully in var/"